// Bookmark Manager API — entrypoint
// See PRODUCT_SPEC.md for full requirements
// The agent will build this out across tasks T1-T6

import express from "express";
import Database from "better-sqlite3";

const app = express();
const PORT = Number(process.env.PORT ?? 3000);
const db = new Database("data.db");

type Bookmark = {
  id: number;
  url: string;
  title: string;
  description: string | null;
  folder_id: number | null;
  created_at: string;
  updated_at: string;
};

type Folder = {
  id: number;
  name: string;
  created_at: string;
  updated_at: string;
};

type FolderWithBookmarks = Folder & {
  bookmarks: Bookmark[];
};

db.pragma("foreign_keys = ON");
db.exec(`
  CREATE TABLE IF NOT EXISTS folders (
    id INTEGER PRIMARY KEY,
    name TEXT NOT NULL,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL
  );

  CREATE TABLE IF NOT EXISTS bookmarks (
    id INTEGER PRIMARY KEY,
    url TEXT NOT NULL,
    title TEXT NOT NULL,
    description TEXT,
    folder_id INTEGER REFERENCES folders(id) ON DELETE SET NULL,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL
  )
`);

const bookmarkColumns = db.prepare("PRAGMA table_info(bookmarks)").all() as Array<{ name: string }>;
if (!bookmarkColumns.some((column) => column.name === "folder_id")) {
  db.prepare(
    "ALTER TABLE bookmarks ADD COLUMN folder_id INTEGER REFERENCES folders(id) ON DELETE SET NULL"
  ).run();
}

app.use(express.json());

app.get("/health", (_req, res) => {
  res.status(200).json({ status: "ok" });
});

const isNonEmptyString = (value: unknown): value is string =>
  typeof value === "string" && value.trim().length > 0;

const getBookmarkById = (id: number): Bookmark | undefined =>
  db
    .prepare(
      "SELECT id, url, title, description, folder_id, created_at, updated_at FROM bookmarks WHERE id = ?"
    )
    .get(id) as Bookmark | undefined;

const getFolderById = (id: number): Folder | undefined =>
  db
    .prepare("SELECT id, name, created_at, updated_at FROM folders WHERE id = ?")
    .get(id) as Folder | undefined;

const parsePositiveInteger = (value: string): number | null => {
  const id = Number(value);
  return Number.isInteger(id) && id > 0 ? id : null;
};

const parseFolderIdInput = (value: unknown): number | null | undefined => {
  if (value === undefined) {
    return undefined;
  }

  if (value === null) {
    return null;
  }

  return typeof value === "number" && Number.isInteger(value) && value > 0 ? value : undefined;
};

const isValidFolderReference = (folderId: number | null | undefined): boolean =>
  folderId === undefined || folderId === null || Boolean(getFolderById(folderId));

app.post("/bookmarks", (req, res) => {
  const { url, title, description, folder_id } = req.body ?? {};

  if (!isNonEmptyString(url)) {
    return res.status(400).json({ error: "url is required" });
  }

  if (!isNonEmptyString(title)) {
    return res.status(400).json({ error: "title is required" });
  }

  const parsedFolderId = parseFolderIdInput(folder_id);
  if (folder_id !== undefined && parsedFolderId === undefined) {
    return res.status(400).json({ error: "folder_id must reference an existing folder" });
  }

  if (!isValidFolderReference(parsedFolderId)) {
    return res.status(400).json({ error: "folder_id must reference an existing folder" });
  }

  const now = new Date().toISOString();
  const result = db
    .prepare(
      `INSERT INTO bookmarks (url, title, description, folder_id, created_at, updated_at)
       VALUES (?, ?, ?, ?, ?, ?)`
    )
    .run(
      url.trim(),
      title.trim(),
      typeof description === "string" ? description : null,
      parsedFolderId ?? null,
      now,
      now
    );

  const bookmark = getBookmarkById(Number(result.lastInsertRowid));
  return res.status(201).json(bookmark);
});

app.get("/bookmarks", (_req, res) => {
  const bookmarks = db
    .prepare(
      "SELECT id, url, title, description, folder_id, created_at, updated_at FROM bookmarks ORDER BY id"
    )
    .all() as Bookmark[];

  res.status(200).json(bookmarks);
});

app.get("/bookmarks/:id", (req, res) => {
  const id = parsePositiveInteger(req.params.id);

  if (id === null) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const bookmark = getBookmarkById(id);

  if (!bookmark) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  return res.status(200).json(bookmark);
});

app.put("/bookmarks/:id", (req, res) => {
  const id = parsePositiveInteger(req.params.id);
  const existingBookmark = id === null ? undefined : getBookmarkById(id);

  if (id === null || !existingBookmark) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const { url, title, description, folder_id } = req.body ?? {};

  if (url !== undefined && !isNonEmptyString(url)) {
    return res.status(400).json({ error: "url must be a non-empty string" });
  }

  if (title !== undefined && !isNonEmptyString(title)) {
    return res.status(400).json({ error: "title must be a non-empty string" });
  }

  const parsedFolderId = parseFolderIdInput(folder_id);
  if (folder_id !== undefined && parsedFolderId === undefined) {
    return res.status(400).json({ error: "folder_id must reference an existing folder" });
  }

  if (!isValidFolderReference(parsedFolderId)) {
    return res.status(400).json({ error: "folder_id must reference an existing folder" });
  }

  const now = new Date().toISOString();
  db.prepare(
    `UPDATE bookmarks
     SET url = COALESCE(?, url),
         title = COALESCE(?, title),
         description = ?,
         folder_id = ?,
         updated_at = ?
     WHERE id = ?`
  ).run(
    typeof url === "string" ? url.trim() : null,
    typeof title === "string" ? title.trim() : null,
    description === undefined
      ? existingBookmark.description
      : typeof description === "string"
        ? description
        : null,
    folder_id === undefined ? existingBookmark.folder_id : parsedFolderId,
    now,
    id
  );

  return res.status(200).json(getBookmarkById(id));
});

app.delete("/bookmarks/:id", (req, res) => {
  const id = parsePositiveInteger(req.params.id);

  if (id === null) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const result = db.prepare("DELETE FROM bookmarks WHERE id = ?").run(id);

  if (result.changes === 0) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  return res.status(204).send();
});

app.post("/folders", (req, res) => {
  const { name } = req.body ?? {};

  if (!isNonEmptyString(name)) {
    return res.status(400).json({ error: "name is required" });
  }

  const now = new Date().toISOString();
  const result = db
    .prepare("INSERT INTO folders (name, created_at, updated_at) VALUES (?, ?, ?)")
    .run(name.trim(), now, now);

  return res.status(201).json(getFolderById(Number(result.lastInsertRowid)));
});

app.get("/folders", (_req, res) => {
  const folders = db
    .prepare("SELECT id, name, created_at, updated_at FROM folders ORDER BY id")
    .all() as Folder[];

  return res.status(200).json(folders);
});

app.get("/folders/:id", (req, res) => {
  const id = parsePositiveInteger(req.params.id);
  const folder = id === null ? undefined : getFolderById(id);

  if (id === null || !folder) {
    return res.status(404).json({ error: "folder not found" });
  }

  const bookmarks = db
    .prepare(
      "SELECT id, url, title, description, folder_id, created_at, updated_at FROM bookmarks WHERE folder_id = ? ORDER BY id"
    )
    .all(id) as Bookmark[];

  const folderWithBookmarks: FolderWithBookmarks = { ...folder, bookmarks };
  return res.status(200).json(folderWithBookmarks);
});

app.put("/folders/:id", (req, res) => {
  const id = parsePositiveInteger(req.params.id);
  const folder = id === null ? undefined : getFolderById(id);

  if (id === null || !folder) {
    return res.status(404).json({ error: "folder not found" });

  const now = new Date().toISOString();
  const result = db
    .prepare("INSERT INTO folders (name, created_at, updated_at) VALUES (?, ?, ?)")
    .run(name.trim(), now, now);

  return res.status(201).json(getFolderById(Number(result.lastInsertRowid)));
});

app.get("/folders", (_req, res) => {
  const folders = db
    .prepare("SELECT id, name, created_at, updated_at FROM folders ORDER BY id")
    .all() as Folder[];

  return res.status(200).json(folders);
});

app.get("/folders/:id", (req, res) => {
  const id = parsePositiveInteger(req.params.id);
  const folder = id === null ? undefined : getFolderById(id);

  if (id === null || !folder) {
    return res.status(404).json({ error: "folder not found" });
  }

  const bookmarks = db
    .prepare(
      "SELECT id, url, title, description, folder_id, created_at, updated_at FROM bookmarks WHERE folder_id = ? ORDER BY id"
    )
    .all(id) as Bookmark[];

  const folderWithBookmarks: FolderWithBookmarks = { ...folder, bookmarks };
  return res.status(200).json(folderWithBookmarks);
});

app.put("/folders/:id", (req, res) => {
  const id = parsePositiveInteger(req.params.id);
  const folder = id === null ? undefined : getFolderById(id);

  if (id === null || !folder) {
    return res.status(404).json({ error: "folder not found" });
  }

  const { name } = req.body ?? {};
  if (!isNonEmptyString(name)) {
    return res.status(400).json({ error: "name is required" });
  }

  db.prepare("UPDATE folders SET name = ?, updated_at = ? WHERE id = ?").run(
    name.trim(),
    new Date().toISOString(),
    id
  );

  return res.status(200).json(getFolderById(id));
});

app.delete("/folders/:id", (req, res) => {
  const id = parsePositiveInteger(req.params.id);
  const folder = id === null ? undefined : getFolderById(id);

  if (id === null || !folder) {
    return res.status(404).json({ error: "folder not found" });
  }

  const transaction = db.transaction((folderId: number) => {
    db.prepare("UPDATE bookmarks SET folder_id = NULL, updated_at = ? WHERE folder_id = ?").run(
      new Date().toISOString(),
      folderId
    );
    db.prepare("DELETE FROM folders WHERE id = ?").run(folderId);
  });

  transaction(id);
  return res.status(204).send();
});

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

export default app;

